// Прокси: используем helpers.httpRequest с параметром `formData` — n8n под
// капотом обернёт это в библиотеку form-data, которая правильно собирает
// multipart. Раньше я собирал multipart вручную через Buffer.concat — Python
// (FastAPI/python-multipart) отдавал 400 на этот формат. Через formData это
// должно работать как curl.

const MERGER_URLS = [
  { url: 'http://host.docker.internal:8082/merge', timeout: 8000   },
  { url: 'http://127.0.0.1:8082/merge',            timeout: 180000 }
];

const input = $input.first();
const binary = input.binary || {};
const binaryKeys = Object.keys(binary);
console.log('[table-merger] входных binary-полей:', binaryKeys.length, binaryKeys);

if (binaryKeys.length === 0) {
  return [{ json: { success: false, error: 'Не загружено ни одного файла.' } }];
}

// Собираем массив файлов под одним именем 'files' — Python ждёт List[UploadFile].
const filesArray = [];
for (const key of binaryKeys) {
  const meta = binary[key] || {};
  const buf = await this.helpers.getBinaryDataBuffer(0, key);
  const fname = meta.fileName || (key + '.bin');
  const ctype = meta.mimeType || 'application/octet-stream';
  console.log('[table-merger] file:', fname, 'size:', buf.length, 'type:', ctype);
  filesArray.push({
    value: buf,
    options: { filename: fname, contentType: ctype }
  });
}

let response = null;
let usedUrl = '';
let nonNetworkErr = null;
let lastErrMsg = '';
for (const entry of MERGER_URLS) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: entry.url,
      formData: { files: filesArray },
      encoding: 'arraybuffer',
      returnFullResponse: true,
      timeout: entry.timeout
    });
    console.log('[table-merger] httpRequest', entry.url, 'status:', r.statusCode);
    response = r;
    usedUrl = entry.url;
    break;
  } catch (e) {
    lastErrMsg = (e && e.message) ? e.message : String(e);
    const code = (e.cause && e.cause.code) || e.code || '';
    const isNet = ['ECONNREFUSED','ENOTFOUND','EHOSTUNREACH','EAI_AGAIN','ETIMEDOUT','ECONNABORTED','ECONNRESET'].includes(code)
      || /timeout|econnrefused|enotfound|connect|getaddrinfo/i.test(String(e.message || ''));
    console.log('[table-merger] http err на', entry.url, ':', lastErrMsg, '| code:', code, '| isNet:', isNet);
    if (isNet) continue;
    nonNetworkErr = e;
    break;
  }
}

if (nonNetworkErr) {
  let errMsg = nonNetworkErr.message || 'Ошибка вызова table-merger';
  if (nonNetworkErr.response && nonNetworkErr.response.body) {
    try {
      const txt = Buffer.from(nonNetworkErr.response.body).toString('utf8');
      const parsed = JSON.parse(txt);
      if (parsed && parsed.detail) errMsg = parsed.detail;
      else errMsg = txt.slice(0, 500);
    } catch (_) {
      try {
        errMsg = Buffer.from(nonNetworkErr.response.body).toString('utf8').slice(0, 500);
      } catch (_) {}
    }
  }
  return [{ json: { success: false, error: errMsg } }];
}

if (!response) {
  return [{ json: { success: false, error: 'table-merger сервис недоступен. Запусти start.bat на хост-машине (порт 8082). Последняя ошибка: ' + lastErrMsg } }];
}

const headers = response.headers || {};
const cd = headers['content-disposition'] || headers['Content-Disposition'] || '';
const respContentLength = headers['content-length'] || headers['Content-Length'] || '';
console.log('[table-merger] response content-length:', respContentLength, '| content-disposition:', cd);

let outFilename = 'merged.bin';
let m = cd.match(/filename\*=UTF-8''([^;]+)/i);
if (m) {
  try { outFilename = decodeURIComponent(m[1]); } catch (_) { outFilename = m[1]; }
} else {
  m = cd.match(/filename="?([^";]+)"?/i);
  if (m) outFilename = m[1];
}
const outMime = headers['content-type'] || headers['Content-Type'] || 'application/octet-stream';

const outBuffer = Buffer.isBuffer(response.body) ? response.body : Buffer.from(response.body || []);
console.log('[table-merger] outBuffer size:', outBuffer.length);

if (outBuffer.length === 0) {
  return [{ json: { success: false, error: 'Пустой ответ от Python-сервиса (' + usedUrl + '). content-length: ' + respContentLength + '.' } }];
}

const binaryData = await this.helpers.prepareBinaryData(outBuffer, outFilename, outMime);

return [{
  json: {
    success: true,
    filename: outFilename,
    size: outBuffer.length,
    files: binaryKeys.length,
    debug: { usedUrl: usedUrl, respContentLength: respContentLength }
  },
  binary: { data: binaryData }
}];
